const body = $input.first().json.body;
const comment = body.comment;
const pr = body.pull_request;
const repo = body.repository;

const commentBody = (comment.body || '').trim();
let command = null;

if (commentBody === '/fix-build') command = 'fix-build';
else if (commentBody === '/fix-lint') command = 'fix-lint';
else if (commentBody === '/fix' && comment.in_reply_to_id) command = 'fix';

if (!command) return [];

return [{
  json: {
    command,
    prNumber: pr.number,
    prTitle: pr.title,
    prUrl: pr.html_url,
    headBranch: pr.head.ref,
    headSha: pr.head.sha,
    repoOwner: repo.owner.login,
    repoName: repo.name,
    commentId: comment.id,
    filePath: comment.path || null,
    inReplyToId: comment.in_reply_to_id || null
  }
}];

const ctx = $input.first().json;
const token = $env.GITHUB_TOKEN;

function ghGet(path) {
  return new Promise((resolve, reject) => {
    const https = require('https');
    const url = new URL(`https://api.github.com${path}`);
    const req = https.request({
      hostname: url.hostname,
      path: url.pathname + url.search,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Accept': 'application/vnd.github+json',
        'X-GitHub-Api-Version': '2022-11-28',
        'User-Agent': 'n8n-jump-section'
      }
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) reject(new Error(`HTTP ${res.statusCode}: ${data}`));
        else resolve(JSON.parse(data));
      });
    });
    req.on('error', reject);
    req.end();
  });
}

// PR 변경 파일 조회 및 디코딩
const filesData = await ghGet(`/repos/${ctx.repoOwner}/${ctx.repoName}/pulls/${ctx.prNumber}/files?per_page=30`);

const files = await Promise.all(filesData.map(async (f) => {
  const contentData = await ghGet(`/repos/${ctx.repoOwner}/${ctx.repoName}/contents/${f.filename}?ref=${ctx.headBranch}`);
  const content = Buffer.from((contentData.content || '').replace(/\n/g, ''), 'base64').toString('utf8');
  return { path: f.filename, content, sha: contentData.sha };
}));

// CI 실패 정보 조회
const checkData = await ghGet(`/repos/${ctx.repoOwner}/${ctx.repoName}/commits/${ctx.headSha}/check-runs?per_page=30`);
const failed = (checkData.check_runs || []).filter(c =>
  c.conclusion === 'failure' || c.conclusion === 'timed_out'
);

const ciSection = failed.length > 0
  ? failed.map(c => {
      const lines = [`### ❌ ${c.name}`];
      if (c.output?.summary) lines.push(c.output.summary);
      if (c.output?.text) lines.push(c.output.text.slice(0, 3000));
      return lines.join('\n');
    }).join('\n\n')
  : '(CI 실패 없음)';

const filesContext = files.map(f =>
  `### ${f.path}\n\`\`\`typescript\n${f.content}\n\`\`\``
).join('\n\n');

const userPrompt = `## PR #${ctx.prNumber}: ${ctx.prTitle}\n브랜치: \`${ctx.headBranch}\`\n\n## CI 실패 정보\n\n${ciSection}\n\n---\n\n## 현재 코드\n\n${filesContext}\n\n---\n\nCI 빌드/타입 에러를 분석하여 수정하세요. 원인이 명확한 경우에만 write_file로 제출합니다.`;

const geminiPayload = {
  system_instruction: {
    parts: [{ text: 'TypeScript 전문 개발자입니다. CI 빌드 에러와 타입 에러를 수정합니다.\n\n## 필수 규칙\n\n### Prettier 포맷\n- 들여쓰기: 스페이스 2칸, 세미콜론 항상, 싱글쿼트, 최대 100자, trailing comma 항상\n\n### 수정 원칙\n- CI 에러 원인이 명확하고 수정 방향이 확실한 경우에만 write_file로 제출\n- 불확실하면 해당 파일은 건너뜀\n- 기존 Public API 하위 호환성 유지\n- 수정이 필요 없는 파일은 write_file 생략' }]
  },
  contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
  tools: [{
    functionDeclarations: [{
      name: 'write_file',
      description: '수정된 파일의 전체 내용을 제출합니다.',
      parameters: {
        type: 'OBJECT',
        properties: {
          path: { type: 'STRING', description: '파일 경로' },
          content: { type: 'STRING', description: '파일 전체 내용' },
          description: { type: 'STRING', description: '변경 설명' }
        },
        required: ['path', 'content', 'description']
      }
    }]
  }],
  toolConfig: { functionCallingConfig: { mode: 'AUTO' } },
  generationConfig: { maxOutputTokens: 8192 }
};

return [{ json: { ...ctx, files, geminiPayload } }];

const response = $input.first().json;
const ctx = $('[build] 파일 + CI 조회 및 프롬프트 준비').first().json;

const parts = response.candidates[0].content.parts;
const functionCalls = parts.filter(p => p.functionCall && p.functionCall.name === 'write_file');

if (functionCalls.length === 0) {
  return [{ json: { noChanges: true, ...ctx } }];
}

const fixedFiles = functionCalls.map(p => {
  const original = ctx.files.find(f => f.path === p.functionCall.args.path);
  return {
    path: p.functionCall.args.path,
    content: p.functionCall.args.content,
    description: p.functionCall.args.description,
    sha: original?.sha || null
  };
});

const filesSummary = fixedFiles.map(f => `• \`${f.path}\`: ${f.description}`).join('\n');

return [{ json: { noChanges: false, fixedFiles, filesSummary, ...ctx } }];

const data = $input.first().json;
const { fixedFiles, headBranch, repoOwner, repoName, filesSummary } = data;
const token = $env.GITHUB_TOKEN;

const headers = {
  'Authorization': `Bearer ${token}`,
  'Accept': 'application/vnd.github+json',
  'X-GitHub-Api-Version': '2022-11-28',
  'Content-Type': 'application/json'
};

const baseUrl = `https://api.github.com/repos/${repoOwner}/${repoName}`;

function request(method, url, body) {
  return new Promise((resolve, reject) => {
    const https = require('https');
    const urlObj = new URL(url);
    const options = { hostname: urlObj.hostname, path: urlObj.pathname + urlObj.search, method, headers };
    const req = https.request(options, (res) => {
      let d = '';
      res.on('data', chunk => d += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) reject(new Error(`HTTP ${res.statusCode}: ${d}`));
        else resolve(JSON.parse(d));
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

const refData = await request('GET', `${baseUrl}/git/refs/heads/${headBranch}`);
const baseSha = refData.object.sha;
const commitData = await request('GET', `${baseUrl}/git/commits/${baseSha}`);
const baseTreeSha = commitData.tree.sha;

const newTree = await request('POST', `${baseUrl}/git/trees`, {
  base_tree: baseTreeSha,
  tree: fixedFiles.map(f => ({ path: f.path, mode: '100644', type: 'blob', content: f.content }))
});

const newCommit = await request('POST', `${baseUrl}/git/commits`, {
  message: `fix: fix build errors\n\n${filesSummary}`,
  tree: newTree.sha,
  parents: [baseSha]
});

await request('PATCH', `${baseUrl}/git/refs/heads/${headBranch}`, { sha: newCommit.sha });

return [{ json: { ...data, commitSha: newCommit.sha } }];

